-- IBKR Backfill v5 - includes daily_twr
-- Run migration 004 first: ALTER TABLE public.portfolio_snapshots ADD COLUMN IF NOT EXISTS daily_twr numeric DEFAULT 0;

ON CONFLICT (snapshot_date) DO UPDATE
  SET total_nav = EXCLUDED.total_nav,
      total_unrealized_pnl = EXCLUDED.total_unrealized_pnl,
      deposits_withdrawals = EXCLUDED.deposits_withdrawals,
      daily_twr = EXCLUDED.daily_twr;

-- open_positions (2026-05-15)
ON CONFLICT (symbol) DO UPDATE
  SET entry_price_actual = EXCLUDED.entry_price_actual,
      entry_date_actual = EXCLUDED.entry_date_actual,
      position_size_actual = EXCLUDED.position_size_actual,
      pct_of_nav = EXCLUDED.pct_of_nav,
      current_price = EXCLUDED.current_price,
      unrealized_pnl = EXCLUDED.unrealized_pnl,
      unrealized_pnl_pct = EXCLUDED.unrealized_pnl_pct,
      last_synced_at = now();

-- closed_trades
DELETE FROM public.closed_trades WHERE symbol IN ('RHM','PANW');
